sql:
SELECT COUNT(shareholder_id) AS number_of_shareholders
FROM shareholders
WHERE share_class_id = 1;

SELECT COUNT(share_class_id) AS seed_count, share_class_name
FROM share_classes
GROUP BY share_class_name;

SELECT COUNT(*) AS total_shareholders
FROM shareholders
WHERE share_class_id = (SELECT share_class_id FROM share_classes WHERE share_class_name = 'A');

SELECT COUNT(DISTINCT shareholder_id) AS NumberOfShareholders
FROM dividend_payments
WHERE payment_date BETWEEN '2023-03-01' AND '2023-05-31';

external_knowledge:
- In the metaphor, gardeners (shareholders) plant seeds (invest in shares) and nurture (hold shares over time), resulting in a harvest (receiving dividends).;
- The frequency and quantity of the harvest (dividends) can differ based on the type of garden (share class) and the season (payment frequency).;
- The total harvested quantity (total dividends received) is a measure of the gardeners' (shareholders') success in their cultivation (investments).;
- The final results are presented alphabetically by the gardeners' (shareholders') names.

sql:
SELECT SUM(amount_paid) AS total_amount_paid, COUNT(payment_id) AS number_of_payments
FROM dividend_payments
WHERE status = 'completed';

SELECT COUNT(*) AS total_dividends
FROM dividends
WHERE currency_code = 'USD';

SELECT currency_code, AVG(dividend_rate) AS average_dividend_rate
FROM dividends
GROUP BY currency_code;

SELECT SUM(dp.amount_paid) AS total_amount_paid
FROM dividend_payments dp
WHERE dp.currency_code = 'GBP' AND dp.payment_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT SUM(amount_paid) AS total_amount_paid
FROM dividend_payments
WHERE dividend_id = 1;

SELECT SUM(amount_paid) AS total_amount_paid
FROM dividend_payments
WHERE payment_date = '2023-02-28';
